package org.jsoup.helper;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources/requirement.feature",
    glue = "org.jsoup.helper.steps",
    plugin = {"pretty"}
)
public class CucumberTest {
}

package org.jsoup.helper.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.jsoup.Jsoup;
import org.jsoup.nodes.Document;
import org.jsoup.parser.Parser;

import java.io.ByteArrayInputStream;
import java.io.IOException;
import java.io.InputStream;
import java.nio.charset.Charset;
import java.nio.charset.UnsupportedCharsetException;

import static org.junit.Assert.*;

public class StepDefs {

    private Document document;
    private String charsetName;

    @Given("an HTML document with a meta charset {string}")
    public void an_html_document_with_a_meta_charset(String charset) {
        charsetName = charset;
        // Create an HTML document with the specified charset
        String html = String.format(
            "<!DOCTYPE html><html><head><meta charset=\"%s\"><title>Test</title></head><body><p>One</p></body></html>",
            charset
        );

        // Create input stream with the HTML content
        InputStream inputStream = new ByteArrayInputStream(html.getBytes());

        // Parse the document
        try {
            document = Jsoup.parse(inputStream, charset, "http://example.com/");
        } catch (IOException e) {
            // This should not happen with ByteArrayInputStream, but handle it anyway
            throw new RuntimeException("Error parsing HTML document", e);
        }
    }

    @Given("the system supports decoding {string} but not encoding it")
    public void the_system_supports_decoding_but_not_encoding_it(String charset) {
        // This step represents that the system can decode the charset but encoding fails
        // In the context of the bug, ISO-2022-CN can be decoded but there might be issues encoding it
        try {
            Charset availableCharset = Charset.forName(charset);
            // Check that the charset is available for decoding
            assertNotNull(availableCharset);
        } catch (UnsupportedCharsetException e) {
            // For this test, we're simulating the scenario where the charset exists but
            // there's a problem with encoding it in certain contexts
            fail("Charset " + charset + " is not supported for decoding");
        }
    }

    @When("the document is parsed from an input stream")
    public void the_document_is_parsed_from_an_input_stream() {
        // The parsing already happened in the Given step,
        // but we could add additional logic here if needed
        assertNotNull(document);
    }

    @Then("the detected charset for the document should be {string}")
    public void the_detected_charset_for_the_document_should_be(String expectedCharset) {
        // Check the charset used for the document
        String actualCharset = document.charset() != null ? document.charset().name() : "UTF-8";
        assertEquals(expectedCharset, actualCharset);
    }

    @Then("the document content should be correctly parsed as {string}")
    public void the_document_content_should_be_correctly_parsed_as(String expectedContent) {
        String actualContent = document.body().text();
        assertEquals(expectedContent, actualContent);
    }

    @Then("the rendered HTML should contain {string}")
    public void the_rendered_html_should_contain(String expectedElement) {
        String renderedHtml = document.toString();
        assertTrue(renderedHtml.contains(expectedElement));
    }
}

